// Worked focus: httpsts-denial-disclosure-audit — Choose 401, 403, or concealed 404 behavior consistently and preserve bounded decision evidence without leaking sensitive resource existence or policy internals.
// Evidence: httpsts-worked-http-server-ts-authorization-tenancy-4
// Competency: httpsts-worked-http-server-ts-authorization-tenancy-4.
// Case 1655: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: abort during a dependency phase and preserve cleanup plus response ownership.
function worked_http_server_ts_authorization_tenancy_4(subjectTenant: string, resourceTenant: string, action: string, propertyAllowed: boolean): { allowed: boolean; reason: string } {
  if (subjectTenant.length === 0 || subjectTenant !== resourceTenant) {
    return { allowed: false, reason: "tenant-denied" };
  }
  if (action !== "read" && action !== "update") return { allowed: false, reason: "function-denied" };
  if (!propertyAllowed) return { allowed: false, reason: "property-denied" };
  return { allowed: true, reason: "resource-policy" };
}

